import Nav from '../components/nav'
import Record from '../components/record'
import { getAll, insert } from '../lib/db'
import createPersistedState from 'use-persisted-state';

const useCounterState = createPersistedState('my-group');

export default function Home() {
  const [records, setRecords] = useCounterState(getAll('records'))
  return (
    <div>
      <Nav />
      <main>
        <h1>Welcome to Contatempo</h1>
        <button onClick={() => {
            const newRecord = { start: new Date().toISOString(), end: 'b' }
            insert('records', newRecord)
            setRecords([...records, newRecord])
          }}>Add</button>
        <ul>
          {records.map(record => <Record key={record.start} record={record} />)}
        </ul>
      </main>
    </div>
  );
}
